var od = Math.floor(Date.now()/1000) - 86400;
msg.topic = "SELECT ts, node, velicina, value, unit FROM merania WHERE ts >= " + od + " AND value IS NOT NULL AND node = 'uzol1' ORDER BY ts ASC;";
return msg;

var rows = msg.payload;
if (!rows || rows.length === 0) { node.warn('Žiadne historické dáta'); return null; }

var series = {};
rows.forEach(function(r) {
    var key = r.node + '/' + r.velicina;
    if (!series[key]) series[key] = [];
    series[key].push({ x: r.ts * 1000, y: r.value });
});

Object.keys(series).forEach(function(key) {
    var velicinaName = key.split('/')[1];
    node.send({
        topic: key,
        payload: [{
            series: [velicinaName],
            data: [series[key]]
        }]
    });
});
return null;

